import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';

const MetaAds = () => {
  const { makeRequest, user } = useAuth();
  const [pricing, setPricing] = useState([]);
  const [leads, setLeads] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editingPricing, setEditingPricing] = useState(null);
  const [loading, setLoading] = useState(true);
  const [syncing, setSyncing] = useState(false);
  const [message, setMessage] = useState('');
  const [activeTab, setActiveTab] = useState('pricing');
  const [filtroRegiao, setFiltroRegiao] = useState('');
  const [filtroEstado, setFiltroEstado] = useState('');
  const [filtroStatus, setFiltroStatus] = useState('');
  const [campaigns, setCampaigns] = useState([]);
  const [selectedCampaign, setSelectedCampaign] = useState('');
  const [dateRange, setDateRange] = useState('last_30d');
  const [apiStatus, setApiStatus] = useState(null);
  const [tokenStatus, setTokenStatus] = useState(null);
  const [formData, setFormData] = useState({
    city: '',
    state: '',
    country: 'BR',
    cost_per_lead: '',
    spend: '',
    leads: '',
    date_range: 'manual'
  });

  // Verificar se usuário é admin
  const isAdmin = user?.tipo === 'admin';

  useEffect(() => {
    if (activeTab === 'pricing') {
      fetchPricing();
      fetchCampaigns();
    } else {
      fetchLeads();
    }
  }, [activeTab]);

  useEffect(() => {
    testApiConnection();
  }, []);

  const fetchPricing = async () => {
    try {
      const params = new URLSearchParams();
      if (filtroRegiao) params.append('cidade', filtroRegiao);
      if (filtroEstado) params.append('estado', filtroEstado);
      if (filtroStatus) params.append('status', filtroStatus);

      const response = await makeRequest(`/meta-ads/pricing?${params}`);
      const data = await response.json();

      if (response.ok) {
        setPricing(data);
      } else {
        console.error('Erro ao carregar preços:', data.error);
        setMessage('Erro ao carregar preços: ' + data.error);
      }
    } catch (error) {
      console.error('Erro ao carregar preços:', error);
      setMessage('Erro ao conectar com o servidor');
    } finally {
      setLoading(false);
    }
  };

  const fetchLeads = async () => {
    try {
      const response = await makeRequest('/meta-ads/leads');
      const data = await response.json();

      if (response.ok) {
        setLeads(data);
      } else {
        console.error('Erro ao carregar leads:', data.error);
        setMessage('Erro ao carregar leads: ' + data.error);
      }
    } catch (error) {
      console.error('Erro ao carregar leads:', error);
      setMessage('Erro ao conectar com o servidor');
    } finally {
      setLoading(false);
    }
  };

  const fetchCampaigns = async () => {
    try {
      const response = await makeRequest('/meta-ads/campaigns');
      const data = await response.json();

      if (response.ok) {
        setCampaigns(data.data || []);
      } else {
        console.error('Erro ao carregar campanhas:', data.error);
        setMessage('Erro ao carregar campanhas: ' + (data.error || 'Erro desconhecido'));
      }
    } catch (error) {
      console.error('Erro ao carregar campanhas:', error);
      setMessage('Erro ao conectar com o servidor');
    }
  };

  const testApiConnection = async () => {
    try {
      const response = await makeRequest('/meta-ads/test-connection');
      const data = await response.json();
      setApiStatus(data);
      setTokenStatus(data.tokenStatus);
    } catch (error) {
      setApiStatus({ 
        success: false, 
        message: 'Erro ao testar conexão',
        error: error.message || 'Erro desconhecido'
      });
    }
  };

  const checkTokenStatus = async () => {
    try {
      const response = await makeRequest('/meta-ads/token-status');
      const data = await response.json();
      setTokenStatus(data);
    } catch (error) {
      console.error('Erro ao verificar status do token:', error);
    }
  };

  const extendToken = async () => {
    try {
      setLoading(true);
      const response = await makeRequest('/meta-ads/extend-token', {
        method: 'POST'
      });
      const data = await response.json();

      if (response.ok) {
        setMessage(`✅ ${data.message}\n\n🔑 Novo token: ${data.newToken}\n\n⚠️ Copie e atualize seu .env!`);
        checkTokenStatus();
      } else {
        setMessage('❌ Erro ao renovar token: ' + (data.error || 'Erro desconhecido'));
      }
    } catch (error) {
      setMessage('❌ Erro ao renovar token: ' + (error.message || 'Erro desconhecido'));
    } finally {
      setLoading(false);
    }
  };

  const syncCampaigns = async () => {
    try {
      setSyncing(true);
      setMessage(''); // Limpar mensagens anteriores
      const response = await makeRequest('/meta-ads/sync-campaigns', {
        method: 'POST'
      });
      const data = await response.json();

      if (response.ok) {
        setMessage(data.message);
        fetchPricing();
        setTimeout(() => setMessage(''), 5000);
      } else {
        setMessage('Erro ao sincronizar: ' + (data.error || 'Erro desconhecido'));
      }
    } catch (error) {
      setMessage('Erro ao sincronizar campanhas: ' + (error.message || 'Erro desconhecido'));
    } finally {
      setSyncing(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      let response;
      if (editingPricing) {
        response = await makeRequest(`/meta-ads/pricing/${editingPricing.id}`, {
          method: 'PUT',
          body: JSON.stringify(formData)
        });
      } else {
        response = await makeRequest('/meta-ads/pricing', {
          method: 'POST',
          body: JSON.stringify(formData)
        });
      }

      const data = await response.json();

      if (response.ok) {
        setMessage(editingPricing ? 'Preço atualizado com sucesso!' : 'Preço cadastrado com sucesso!');
        setShowModal(false);
        setEditingPricing(null);
        setFormData({
          cidade: '',
          estado: '',
          preco_por_lead: '',
          campanha_id: '',
          campanha_nome: '',
          periodo_inicio: '',
          periodo_fim: '',
          observacoes: '',
          status: 'ativo'
        });
        fetchPricing();
        setTimeout(() => setMessage(''), 3000);
      } else {
        setMessage('Erro ao salvar preço: ' + data.error);
      }
    } catch (error) {
      console.error('Erro ao salvar preço:', error);
      setMessage('Erro ao salvar preço');
    }
  };

  const handleEdit = (pricing) => {
    setEditingPricing(pricing);
    setFormData({
      city: pricing.city || pricing.region?.split(' - ')[0] || '',
      state: pricing.state || pricing.region?.split(' - ')[1] || '',
      country: pricing.country || 'BR',
      cost_per_lead: pricing.cost_per_lead || '',
      spend: pricing.spend || '',
      leads: pricing.leads || '',
      date_range: pricing.date_range || 'manual'
    });
    setShowModal(true);
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  const formatarPreco = (preco) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL'
    }).format(preco);
  };

  const formatarData = (data) => {
    return new Date(data).toLocaleDateString('pt-BR');
  };

  const estados = [
    'AC', 'AL', 'AP', 'AM', 'BA', 'CE', 'DF', 'ES', 'GO', 'MA',
    'MT', 'MS', 'MG', 'PA', 'PB', 'PR', 'PE', 'PI', 'RJ', 'RN',
    'RS', 'RO', 'RR', 'SC', 'SP', 'SE', 'TO'
  ];

  if (!isAdmin) {
    return (
      <div className="container">
        <div className="alert alert-warning">
          <h3>🔒 Acesso Restrito</h3>
          <p>Apenas administradores podem acessar as configurações do Meta Ads.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="container">
      <div className="header">
        <h1>Meta Ads - Preços por Lead</h1>
        <p>Gerencie os preços por lead do Meta Ads por cidade</p>
      </div>

      {message && (
        <div className={`alert ${message.includes('sucesso') ? 'alert-success' : 'alert-error'}`}>
          {typeof message === 'string' ? message : JSON.stringify(message)}
        </div>
      )}

      <div className="tabs">
        <button 
          className={`tab ${activeTab === 'pricing' ? 'active' : ''}`}
          onClick={() => setActiveTab('pricing')}
        >
          Preços por Cidade
        </button>
        <button 
          className={`tab ${activeTab === 'leads' ? 'active' : ''}`}
          onClick={() => setActiveTab('leads')}
        >
          Leads do Meta Ads
        </button>
        <button 
          className={`tab ${activeTab === 'api' ? 'active' : ''}`}
          onClick={() => setActiveTab('api')}
        >
          🔗 API Integration
        </button>
      </div>

      {activeTab === 'pricing' && (
        <>
          <div className="actions">
            <button 
              className="btn btn-primary"
              onClick={() => setShowModal(true)}
            >
              ➕ Adicionar Preço
            </button>
          </div>

          <div className="filters">
            <input
              type="text"
                          placeholder="Filtrar por região..."
            value={filtroRegiao}
            onChange={(e) => setFiltroRegiao(e.target.value)}
              className="filter-input"
            />
            <select
              value={filtroEstado}
              onChange={(e) => setFiltroEstado(e.target.value)}
              className="filter-select"
            >
              <option value="">Todos os estados</option>
              {estados.map(estado => (
                <option key={estado} value={estado}>{estado}</option>
              ))}
            </select>
            <select
              value={filtroStatus}
              onChange={(e) => setFiltroStatus(e.target.value)}
              className="filter-select"
            >
              <option value="">Todos os status</option>
              <option value="ativo">Ativo</option>
              <option value="inativo">Inativo</option>
            </select>
            <button 
              className="btn btn-secondary"
              onClick={fetchPricing}
            >
              🔍 Filtrar
            </button>
          </div>

          <div className="table-container">
            <table className="table">
              <thead>
                <tr>
                  <th>Cidade</th>
                  <th>Estado</th>
                  <th>País</th>
                  <th>Custo por Lead</th>
                  <th>Gastos</th>
                  <th>Leads</th>
                  <th>Período</th>
                  <th>Ações</th>
                </tr>
              </thead>
              <tbody>
                {pricing.map(item => (
                  <tr key={item.id}>
                    <td>{item.city || item.region?.split(' - ')[0] || 'N/A'}</td>
                    <td>{item.state || item.region?.split(' - ')[1] || 'BR'}</td>
                    <td>{item.country || 'BR'}</td>
                    <td>
                      <span className="price">{formatarPreco(item.cost_per_lead)}</span>
                    </td>
                    <td>
                      <span className="price">{formatarPreco(item.spend)}</span>
                    </td>
                    <td>{item.leads || 0}</td>
                    <td>{item.date_range || '-'}</td>
                    <td>
                      <button 
                        className="btn btn-sm btn-secondary"
                        onClick={() => handleEdit(item)}
                      >
                        ✏️ Editar
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </>
      )}

      {activeTab === 'leads' && (
        <div className="table-container">
          <table className="table">
            <thead>
              <tr>
                <th>Paciente</th>
                <th>Campanha</th>
                <th>Custo do Lead</th>
                <th>Cidade</th>
                <th>Data</th>
                <th>Fonte</th>
              </tr>
            </thead>
            <tbody>
              {leads.map(lead => (
                <tr key={lead.id}>
                  <td>
                    <div>
                      <strong>{lead.pacientes?.nome}</strong>
                      <div style={{ fontSize: '0.75rem', color: '#9ca3af' }}>
                        {lead.pacientes?.telefone}
                      </div>
                    </div>
                  </td>
                  <td>{lead.campanha_nome || '-'}</td>
                  <td>
                    {lead.custo_lead ? (
                      <span className="price">{formatarPreco(lead.custo_lead)}</span>
                    ) : '-'}
                  </td>
                  <td>{lead.cidade_lead || '-'}</td>
                  <td>{lead.data_lead ? formatarData(lead.data_lead) : '-'}</td>
                  <td>
                    <span className="badge badge-info">{lead.fonte_lead}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {activeTab === 'api' && (
                  <div className="api-integration">
          <div className="api-status">
            <h3>🔗 Status da API</h3>
            {apiStatus && (
              <div className={`status-card ${apiStatus.success ? 'success' : 'error'}`}>
                <div className="status-icon">
                  {apiStatus.success ? '✅' : '❌'}
                </div>
                <div className="status-content">
                  <h4>{apiStatus.message}</h4>
                  {apiStatus.campaignsCount && (
                    <p>Campanhas encontradas: {apiStatus.campaignsCount}</p>
                  )}
                  {apiStatus.error && (
                    <p className="error-details">
                      {typeof apiStatus.error === 'string' 
                        ? apiStatus.error 
                        : JSON.stringify(apiStatus.error, null, 2)
                      }
                    </p>
                  )}
                </div>
              </div>
            )}

            {tokenStatus && (
              <div className="token-status">
                <h4>🔑 Status do Token</h4>
                <div className={`token-card ${tokenStatus.needsRenewal ? 'warning' : 'success'}`}>
                  <div className="token-info">
                    <p><strong>Válido:</strong> {tokenStatus.isValid ? '✅ Sim' : '❌ Não'}</p>
                    {tokenStatus.expires && tokenStatus.expires !== 'never' && (
                      <p><strong>Expira em:</strong> {tokenStatus.expires} ({tokenStatus.daysLeft} dias)</p>
                    )}
                    {tokenStatus.expires === 'never' && (
                      <p><strong>Expiração:</strong> ♾️ Nunca expira</p>
                    )}
                    {tokenStatus.needsRenewal && (
                      <p className="warning-text">⚠️ Token precisa ser renovado!</p>
                    )}
                  </div>
                  {tokenStatus.needsRenewal && (
                    <button 
                      className="btn btn-warning"
                      onClick={extendToken}
                      disabled={loading}
                    >
                      🔄 Renovar Token (60 dias)
                    </button>
                  )}
                </div>
              </div>
            )}
          </div>

          <div className="api-actions">
            <h3>🔄 Ações da API</h3>

            <div className="action-buttons">
              <button 
                className="btn btn-primary"
                onClick={testApiConnection}
                disabled={loading}
              >
                🔍 Testar Conexão
              </button>

              <button 
                className="btn btn-secondary"
                onClick={syncCampaigns}
                disabled={syncing}
                style={{ position: 'relative' }}
              >
                {syncing ? (
                  <>
                    <span className="spinner"></span>
                    Sincronizando...
                  </>
                ) : (
                  <>🔄 Sincronizar Campanhas</>
                )}
              </button>
            </div>

            {campaigns.length > 0 && (
              <div className="campaigns-list">
                <h4>📊 Campanhas Disponíveis</h4>
                <div className="campaigns-grid">
                  {campaigns.map(campaign => (
